package com.google.gson.protobuf.generated;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.protobuf.Descriptors;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class BagTest {

  private static Descriptors.FileDescriptor mockDescriptor;

  @BeforeAll
  static void setUp() throws Exception {
    // Use reflection to set the private static field 'descriptor' in Bag class
    mockDescriptor = mock(Descriptors.FileDescriptor.class);
    Field descriptorField = Bag.class.getDeclaredField("descriptor");
    descriptorField.setAccessible(true);
    descriptorField.set(null, mockDescriptor);
  }

  @Test
  void testGetDescriptor_returnsDescriptorField() {
    Descriptors.FileDescriptor result = Bag.getDescriptor();
    assertNotNull(result);
    assertSame(mockDescriptor, result);
  }
}
